sql:
SELECT users.role, users.email
FROM audit_logs
JOIN users ON audit_logs.user_id = users.user_id;

external_knowledge:
- "basking in the sun of abundance" metaphorically refers to regions receiving significantly more funding;
- "a one-and-a-half-fold average glow of financial support" means receiving more than 1.5 times the average amount of grants given across all regions;
- "how bright is their shine" metaphorically refers to the total amount of grants each region has received;
- "sunlit regions" metaphorically means regions with high funding, and "in the order of their radiance" means sorted by the total grant amount in descending order.

sql:
SELECT SUM(amount) AS total_amount_allocated
FROM grants
WHERE program_id = (SELECT program_id FROM programs WHERE program_name = 'CAA');

SELECT description, frequency
FROM report_types
WHERE report_type = 'Grant Allocation Report';

SELECT program_name, budget
FROM programs
WHERE status != 'completed';

SELECT program_name, budget 
FROM programs 
WHERE budget > (SELECT AVG(budget) FROM programs);

SELECT grant_id, region_id, year, amount
FROM grants
WHERE approved_by = 'John Doe' AND region_id = 0;
